class Solution {
    public int minSwapsCouples(int[] row) {
        int n = row.length;
        int[] pos = new int[n];
        for (int i = 0; i < n; i++) {
            pos[row[i]] = i;
        }
        int swaps = 0;
        for (int i = 0; i < n; i += 2) {
            int current = row[i];
            int partner = current ^ 1;
            if (row[i + 1] == partner) continue;
            int j = pos[partner];
            int temp = row[i + 1];
            row[i + 1] = row[j];
            row[j] = temp;
            pos[partner] = i + 1;
            pos[temp] = j;
            swaps++;
        }
        return swaps;
    }
}

